from flask import Flask, request, jsonify
from flask_limiter import Limiter
from flask_limiter.util import get_remote_address
from elasticsearch import Elasticsearch

app = Flask(__name__)
limiter = Limiter(app, key_func=get_remote_address)

# Initialize Elasticsearch client
es = Elasticsearch(['http://localhost:9200'])

# Rate limiting configuration
SEARCH_RATE_LIMIT = "10 per minute"

@app.route('/api/search', methods=['GET'])
@limiter.limit(SEARCH_RATE_LIMIT)
def search_products():
    query = request.args.get('q', '')
    if not query:
        return jsonify({"error": "Query parameter 'q' is required"}), 400

    # Elasticsearch query
    es_query = {
        "query": {
            "multi_match": {
                "query": query,
                "fields": ["name", "description"]
            }
        }
    }

    try:
        response = es.search(index="products", body=es_query)
        products = response['hits']['hits']
        return jsonify([product['_source'] for product in products])
    except Exception as e:
        return jsonify({"error": "An error occurred while searching for products"}), 500

if __name__ == '__main__':
    app.run(debug=True)